function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function safeBool(v) {
  if (v === true) return true;
  if (typeof v === 'string') return v.trim().toLowerCase() === 'true';
  return false;
}
function hasValidJson(v) {
  const s = safeStr(v);
  if (!s || s === '{}' || s === 'null') return false;
  try {
    const p = JSON.parse(s);
    return p && typeof p === 'object' && !Array.isArray(p);
  } catch (e) { return false; }
}

const rows = $input.all().map(i => i.json || {});
const total = rows.length;

function countIf(fn) { return rows.filter(fn).length; }

const nextcloudDone = countIf(r => {
  const f = safeStr(r.nextcloudFolder);
  return f && f.toLowerCase() !== 'null' && f !== '-';
});

const bewertungDone = countIf(r =>
  safeStr(r.summaryText).length >= 50 &&
  hasValidJson(r.analysisJson) &&
  safeStr(r.lastAnalysisAt).length > 0
);

const p1Done = countIf(r => safeStr(r.contentCreatedAt).length > 0);
const p2Done = countIf(r => safeStr(r.imagePrompt).length > 0);
const p3Done = countIf(r => safeStr(r.imageFinalPath).length > 0);

// FIX (2026-07-18): status/visualStatus sind seit dem Multi-Agent-Rewrite tote Spalten -
// niemand schreibt sie mehr, sie stehen dauerhaft leer/veraltet. Alle drei Anomalie-Checks
// prueften bislang gegen diese toten Felder und lieferten daher IMMER "0 Anomalien",
// unabhaengig vom tatsaechlichen Zustand der Pipeline. Umgestellt auf die echten,
// aktuell befuellten Felder contentStage/sharepicNeedStage/imageStage.

// Anomalie 1: Bewertung haengt fest (contentStage=needs_summary, aber inhaltlich fertig)
const bewertungStuck = rows.filter(r =>
  safeStr(r.contentStage) === 'needs_summary' &&
  safeStr(r.summaryText).length >= 50 &&
  hasValidJson(r.analysisJson) &&
  safeStr(r.lastAnalysisAt).length > 0
);

// Anomalie 1b: Ingestion hat einen bereits weit fortgeschrittenen Vorgang zurueckgesetzt
// (contentStage=needs_summary, aber P1 hat bereits Content erzeugt). Das kann NICHT vom
// eigenen Reset-Pfad der Bewertung stammen (der liegt zeitlich vor jeder Content-Erzeugung) -
// nur "Update bekannter Vorgang" in Ingestion konnte das ueberschreiben (Fix 06.07.2026:
// setzt contentStage bei bekannten Vorgaengen nur noch bei echter Dokumentaenderung zurueck).
const ingestionReset = rows.filter(r =>
  safeStr(r.contentStage) === 'needs_summary' &&
  (safeStr(r.websiteHeadline).length > 0 || safeStr(r.contentCreatedAt).length > 0)
);

// Anomalie 2: Bild-Status haengt fest, obwohl schon ein Bild/Post existiert.
// Aktuelle Fehler-Endzustaende aus P6 (ALLRIS_P6_Bildgenerierung, Stand 2026-07-18):
// imageStage='upload_failed'|'qa_failed'|'topic_error_final'.
const IMAGE_RETRY_STATES = new Set([
  'upload_failed', 'qa_failed', 'topic_error_final'
]);
const visualStuck = rows.filter(r =>
  IMAGE_RETRY_STATES.has(safeStr(r.imageStage)) &&
  (safeStr(r.imageFinalPath).length > 0 || safeStr(r.imageCreatedAt).length > 0 || safeBool(r.wordpressPosted))
);

function esc(s) {
  return safeStr(s)
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function pct(n) { return total > 0 ? Math.round((n / total) * 100) : 0; }

function stageRow(label, done) {
  return '<tr><td>' + esc(label) + '</td><td>' + done + ' / ' + total + '</td><td>' +
    '<div class="bar"><div class="fill" style="width:' + pct(done) + '%"></div></div>' +
    '</td><td class="pct">' + pct(done) + '%</td></tr>';
}

function anomalyRows(list, hint) {
  if (list.length === 0) return '<tr><td colspan="6" class="empty">keine</td></tr>';
  return list.map(r =>
    '<tr><td>' + esc(r.vorgangsnummer) + '</td><td>' + esc(r.title).slice(0, 60) + '</td><td>' +
    esc(r.contentStage) + '</td><td>' + esc(r.sharepicNeedStage) + '</td><td>' + esc(r.imageStage) + '</td><td>' + esc(hint) + '</td></tr>'
  ).join('\n');
}

const now = new Date().toLocaleString('de-DE', { timeZone: 'Europe/Berlin' });

const html = '<!DOCTYPE html>' +
'<html lang="de">' +
'<head>' +
'<meta charset="utf-8">' +
'<title>ALLRIS Status-Uebersicht</title>' +
'<style>' +
'  body { font-family: -apple-system, Segoe UI, Arial, sans-serif; background:#0f1115; color:#e6e6e6; margin:0; padding:32px; }' +
'  h1 { font-size:20px; margin-bottom:4px; }' +
'  .meta { color:#9aa0a6; font-size:13px; margin-bottom:24px; }' +
'  table { border-collapse: collapse; width:100%; margin-bottom:32px; }' +
'  th, td { text-align:left; padding:8px 12px; border-bottom:1px solid #2a2d34; font-size:14px; }' +
'  th { color:#9aa0a6; font-weight:600; font-size:12px; text-transform:uppercase; letter-spacing:0.04em; }' +
'  .bar { background:#2a2d34; border-radius:4px; height:8px; width:160px; overflow:hidden; }' +
'  .fill { background:#5b8def; height:100%; }' +
'  .pct { color:#9aa0a6; width:48px; }' +
'  .empty { color:#5f6368; font-style:italic; }' +
'  h2 { font-size:15px; margin-top:8px; margin-bottom:8px; color:#e6e6e6; }' +
'  .hint { color:#f2b950; font-size:12px; margin-bottom:12px; }' +
'</style>' +
'</head>' +
'<body>' +
'  <h1>ALLRIS Pipeline &mdash; Status-Uebersicht</h1>' +
'  <div class="meta">Stand: ' + now + ' &middot; ' + total + ' Vorgaenge insgesamt</div>' +
'  <table>' +
'    <thead><tr><th>Stufe</th><th>Fertig</th><th></th><th></th></tr></thead>' +
'    <tbody>' +
       stageRow('Nextcloud (Dokumente hochgeladen)', nextcloudDone) +
       stageRow('Bewertung (Summary + Analyse)', bewertungDone) +
       stageRow('P1 Content erzeugt', p1Done) +
       stageRow('P2 Visual Prompt vorhanden', p2Done) +
       stageRow('P3 Bild fertig', p3Done) +
'    </tbody>' +
'  </table>' +
'  <h2>Bewertung haengt fest (contentStage=needs_summary trotz fertiger Analyse)</h2>' +
'  <div class="hint">' + bewertungStuck.length + ' Vorgaenge &mdash; werden vom Idempotenz-Guard beim naechsten Bewertung-Lauf automatisch korrigiert. Ursache kann Bewertungs eigener Parse-Fehler-Pfad sein ODER ein erneuter Ingestion-Reset (siehe naechste Tabelle).</div>' +
'  <table>' +
'    <thead><tr><th>Vorgangsnummer</th><th>Titel</th><th>contentStage</th><th>sharepicNeedStage</th><th>imageStage</th><th>Hinweis</th></tr></thead>' +
'    <tbody>' +
       anomalyRows(bewertungStuck, 'wartet auf naechsten Bewertung-Lauf (Guard)') +
'    </tbody>' +
'  </table>' +
'  <h2>Von Ingestion zurueckgesetzt (contentStage=needs_summary trotz bereits erzeugtem Content)</h2>' +
'  <div class="hint">' + ingestionReset.length + ' Vorgaenge &mdash; P1 hat hier schon Content erzeugt, contentStage kann also nur durch Ingestions "Update bekannter Vorgang" zurueckgefallen sein, nicht durch Bewertung selbst. Seit dem Fix vom 06.07.2026 sollte das nur noch bei echter Dokumentaenderung passieren.</div>' +
'  <table>' +
'    <thead><tr><th>Vorgangsnummer</th><th>Titel</th><th>contentStage</th><th>sharepicNeedStage</th><th>imageStage</th><th>Hinweis</th></tr></thead>' +
'    <tbody>' +
       anomalyRows(ingestionReset, 'Content vorhanden, aber contentStage=needs_summary (Ingestion-Reset)') +
'    </tbody>' +
'  </table>' +
'  <h2>Bild-Status haengt fest (Fehler-Status trotz vorhandenem Bild/Post)</h2>' +
'  <div class="hint">' + visualStuck.length + ' Vorgaenge &mdash; benoetigen manuellen Reset (force_image_refresh o.ae.)</div>' +
'  <table>' +
'    <thead><tr><th>Vorgangsnummer</th><th>Titel</th><th>contentStage</th><th>sharepicNeedStage</th><th>imageStage</th><th>Hinweis</th></tr></thead>' +
'    <tbody>' +
       anomalyRows(visualStuck, 'manueller Reset noetig') +
'    </tbody>' +
'  </table>' +
'</body>' +
'</html>';

return [{ json: { html: html } }];
